import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

const Cart = () => {
  const { cart, updateCartItem, removeFromCart, clearCart, getCartTotal } = useCart();
  const { user } = useAuth();
  const [couponCode, setCouponCode] = useState('');
  const [discount, setDiscount] = useState(0);
  const [deliveryOption, setDeliveryOption] = useState('standard');
  const [processing, setProcessing] = useState(false);

  const COUPON_CODES = {
    'NOVA10': 10,
    'SAVE20': 20,
    'STUDENT15': 15
  };

  const handleApplyCoupon = () => {
    const code = couponCode.trim().toUpperCase();
    if (COUPON_CODES[code]) {
      setDiscount(COUPON_CODES[code]);
      alert(`🎉 Coupon applied! £${COUPON_CODES[code]} off`);
    } else {
      alert('❌ Invalid coupon code');
    }
  };

  const calculateShipping = () => {
    const subtotal = getCartTotal();
    if (subtotal >= 50) return 0;
    
    switch (deliveryOption) {
      case 'express':
        return 5.99;
      case 'nextday':
        return 9.99;
      default:
        return subtotal >= 50 ? 0 : 4.99;
    }
  };

  const handleCheckout = async () => {
    if (!user) {
      alert('Please login to place an order');
      window.location.href = '/login';
      return;
    }

    if (cart.length === 0) {
      alert('Your cart is empty');
      return;
    }

    setProcessing(true);

    try {
      const orderPayload = {
        deliveryOption,
        couponCode: discount > 0 ? couponCode.trim() : null
      };

      const response = await axios.post('/api/orders', orderPayload, {
        withCredentials: true
      });

      const d = response.data;
      if (d?.success && d?.data?.order) {
        alert('🎉 Order placed successfully! Thank you!');
        await clearCart();
        window.location.href = '/';
      } else {
        alert(d?.message || 'Failed to place order. Please try again.');
      }
    } catch (error) {
      const msg =
        error.response?.data?.message ||
        error.response?.data?.error ||
        'Failed to place order. Please try again.';
      alert(msg);
    } finally {
      setProcessing(false);
    }
  };

  const subtotal = getCartTotal();
  const shipping = calculateShipping();
  const total = Math.max(0, subtotal + shipping - discount);

  return (
    <>
      <header className="page-header">
        <div className="container">
          <h1>Shopping Cart</h1>
          <ol className="breadcrumb">
            <li><Link to="/">Home</Link></li>
            <li><Link to="/products">Shop</Link></li>
            <li className="active">Cart</li>
          </ol>
        </div>
      </header>

      <main className="cart-page" id="main-content">
        <div className="container">
          <div className="cart-layout">
            <div>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.25rem' }}>
                <h2 style={{ fontSize: '1.4rem' }}>Your Items</h2>
                <button 
                  onClick={clearCart} 
                  style={{ fontSize: '0.8rem', color: 'var(--gray)', background: 'none', border: 'none', cursor: 'pointer', textDecoration: 'underline' }}
                >
                  Clear cart
                </button>
              </div>

              <div className="cart-items" id="cartItemsContainer">
                {cart.length === 0 ? (
                  <div className="empty-cart animate-in">
                    <div className="empty-icon">🛒</div>
                    <h3>Your cart is empty</h3>
                    <p style={{ marginBottom: '1.5rem' }}>Looks like you haven't added anything yet</p>
                    <Link to="/products" className="btn btn-primary">Start Shopping</Link>
                  </div>
                ) : (
                  cart.map((item, idx) => (
                    <div key={item.product} className="cart-item" style={{ animationDelay: `${idx * 0.08}s` }}>
                      <div className="cart-item-img">
                        {item.imageUrl ? (
                          <img src={item.imageUrl} alt={item.name} className="cart-item-img__photo" loading="lazy" />
                        ) : (
                          item.emoji
                        )}
                      </div>
                      <div className="cart-item-info">
                        <div className="cart-item-name">{item.name}</div>
                        <div className="qty-control">
                          <button 
                            className="qty-btn" 
                            onClick={() => updateCartItem(item.product, item.quantity - 1)}
                          >
                            −
                          </button>
                          <span className="qty-display">{item.quantity}</span>
                          <button 
                            className="qty-btn" 
                            onClick={() => updateCartItem(item.product, item.quantity + 1)}
                          >
                            +
                          </button>
                        </div>
                      </div>
                      <div className="cart-item-price">
                        <div className="cart-item-total">£{(item.price * item.quantity).toFixed(2)}</div>
                        <div style={{ fontSize: '0.78rem', color: 'var(--gray)', marginTop: '0.2rem' }}>
                          £{item.price.toFixed(2)} each
                        </div>
                        <button 
                          className="cart-item-remove" 
                          onClick={() => removeFromCart(item.product)}
                        >
                          ✕ Remove
                        </button>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>

            <div>
              <div className="cart-summary">
                <h3>Order Summary</h3>

                <div className="coupon-group">
                  <input
                    type="text"
                    id="couponInput"
                    placeholder="COUPON CODE"
                    value={couponCode}
                    onChange={(e) => setCouponCode(e.target.value)}
                    maxLength="20"
                  />
                  <button className="btn btn-gold btn-sm" onClick={handleApplyCoupon}>
                    Apply
                  </button>
                </div>
                <p style={{ fontSize: '0.72rem', color: 'rgba(255,255,255,0.4)', marginBottom: '1rem' }}>
                  Try: NOVA10 · SAVE20 · STUDENT15
                </p>

                <div style={{ marginBottom: '1rem' }}>
                  <div style={{ fontSize: '0.75rem', fontWeight: 600, letterSpacing: '0.06em', textTransform: 'uppercase', color: 'rgba(255,255,255,0.6)', marginBottom: '0.6rem' }}>
                    Delivery Option
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', cursor: 'pointer', fontSize: '0.85rem', color: 'rgba(255,255,255,0.8)' }}>
                      <input
                        type="radio"
                        name="delivery"
                        value="standard"
                        checked={deliveryOption === 'standard'}
                        onChange={(e) => setDeliveryOption(e.target.value)}
                        style={{ accentColor: 'var(--gold)' }}
                      />
                      Standard (3–5 days) — Free over £50
                    </label>
                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', cursor: 'pointer', fontSize: '0.85rem', color: 'rgba(255,255,255,0.8)' }}>
                      <input
                        type="radio"
                        name="delivery"
                        value="express"
                        checked={deliveryOption === 'express'}
                        onChange={(e) => setDeliveryOption(e.target.value)}
                        style={{ accentColor: 'var(--gold)' }}
                      />
                      Express (1–2 days) — £5.99
                    </label>
                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', cursor: 'pointer', fontSize: '0.85rem', color: 'rgba(255,255,255,0.8)' }}>
                      <input
                        type="radio"
                        name="delivery"
                        value="nextday"
                        checked={deliveryOption === 'nextday'}
                        onChange={(e) => setDeliveryOption(e.target.value)}
                        style={{ accentColor: 'var(--gold)' }}
                      />
                      Next Day — £9.99
                    </label>
                  </div>
                </div>

                {discount > 0 && (
                  <div className="summary-row">
                    <span className="label">Discount</span>
                    <span className="value" style={{ color: '#34d399' }}>-£{discount.toFixed(2)}</span>
                  </div>
                )}
                <div className="summary-row">
                  <span className="label">Subtotal</span>
                  <span className="value">£{subtotal.toFixed(2)}</span>
                </div>
                <div className="summary-row">
                  <span className="label">Shipping</span>
                  <span className="value">{shipping === 0 ? '🎉 Free' : `£${shipping.toFixed(2)}`}</span>
                </div>
                <div className="summary-row total">
                  <span className="label" style={{ color: 'white', fontWeight: 700 }}>Total</span>
                  <span className="value">£{total.toFixed(2)}</span>
                </div>

                <button
                  className="btn btn-gold btn-full"
                  onClick={handleCheckout}
                  disabled={processing || cart.length === 0}
                  style={{ marginTop: '1.5rem', fontSize: '1rem', padding: '1rem' }}
                >
                  {processing ? '⏳ Processing...' : 'Proceed to Checkout →'}
                </button>

                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem', marginTop: '1rem', fontSize: '0.72rem', color: 'rgba(255,255,255,0.4)' }}>
                  🔒 Secure checkout powered by SSL
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>
    </>
  );
};

export default Cart;
